class InteractionHandler:
    def __init__(self):
        self.stdin = sys.stdin
        self.stdout = sys.stdout

    def query_aggregate(self, x, y):
        self.stdout.write(f"? {x} {y}\n")
        self.stdout.flush()
        return int(self.stdin.readline().strip())

    def drill(self, x, y):
        self.stdout.write(f"D {x} {y}\n")
        self.stdout.flush()
        return int(self.stdin.readline().strip())

    def submit_guess(self, cells):
        cell_str = " ".join([f"{r} {c}" for r, c in cells])
        self.stdout.write(f"! {cell_str}\n")
        self.stdout.flush()

class StateModel:
    def __init__(self, width, height, templates):
        self.width = width
        self.height = height
        self.templates = templates
        self.belief_grid = [[0.0 for _ in range(width)] for _ in range(height)]
        self.possible_placements = []
        self._initialize_placements()

    def _initialize_placements(self):
        for t_idx, template in enumerate(self.templates):
            for r in range(self.height):
                for c in range(self.width):
                    if self._can_fit(template, r, c):
                        self.possible_placements.append({
                            'template_idx': t_idx,
                            'r': r, 'c': c,
                            'cells': self._get_cells(template, r, c)
                        })

    def _can_fit(self, template, r, c):
        for dr, dc in template:
            nr, nc = r + dr, c + dc
            if not (0 <= nr < self.height and 0 <= nc < self.width):
                return False
        return True

    def _get_cells(self, template, r, c):
        return [(r + dr, c + dc) for dr, dc in template]

    def update_belief(self, observed_cells, is_drill):
        for p in self.possible_placements:
            match_count = len(set(p['cells']) & set(observed_cells))
            if is_drill:
                weight = 1.0 if match_count == len(p['cells']) else 0.0
            else:
                weight = match_count / len(p['cells'])
            for (pr, pc) in p['cells']:
                self.belief_grid[pr][pc] += weight
